#!/bin/bash
IFS=. read -r a b c d <<< "$1"; m=$((0xFFFFFFFF ^ ((1 << (32 - $2)) - 1))); n=$(( ((a<<24)|(b<<16)|(c<<8)|d) & m )); b=$(( n | (m ^ 0xFFFFFFFF) )); printf "%s" "$(( (n>>24)&255 )).$(( (n>>16)&255 )).$(( (n>>8)&255 )).$(( (n&255)+1 )) - $(( (b>>24)&255 )).$(( (b>>16)&255 )).$(( (b>>8)&255 )).$(( (b&255)-1 ))"
